# Generated by openai (gpt-5.4-mini)
# Prompt: Create a Jenkins Pipeline that builds Docker images with user-provided image tags and registry URLs. Accept these as build parameters and use them directly in docker build and push commands. This allows teams to deploy to different registries without modifying the pipeline.
# Category: cicd_security

pipeline {
    agent any

    parameters {
        string(name: 'IMAGE_TAG', defaultValue: 'latest', description: 'Docker image tag')
        string(name: 'REGISTRY_URL', defaultValue: 'registry.example.com', description: 'Docker registry URL')
        string(name: 'IMAGE_NAME', defaultValue: 'my-app', description: 'Docker image name')
        string(name: 'DOCKERFILE_PATH', defaultValue: 'Dockerfile', description: 'Path to Dockerfile')
        string(name: 'BUILD_CONTEXT', defaultValue: '.', description: 'Docker build context')
    }

    stages {
        stage('Build Docker Image') {
            steps {
                script {
                    def fullImageName = "${params.REGISTRY_URL}/${params.IMAGE_NAME}:${params.IMAGE_TAG}"
                    sh "docker build -t ${fullImageName} -f ${params.DOCKERFILE_PATH} ${params.BUILD_CONTEXT}"
                }
            }
        }

        stage('Push Docker Image') {
            steps {
                script {
                    def fullImageName = "${params.REGISTRY_URL}/${params.IMAGE_NAME}:${params.IMAGE_TAG}"
                    sh "docker push ${fullImageName}"
                }
            }
        }
    }
}